// // This module sets the MSB of the output to 1 if the LSB of the input is 0, and replicates the three most significant bits of the input.
module top_module(
    input [3:0] in,
    output reg [3:0] out
);always @(*) begin
        if (in[0] == 1'b0) begin
            out = {1'b0, in[3:1]};
        end else begin
            out = {1'b1, in[3:1]};
        end
    end

endmodule
